const pick = (j, ...keys) => { for (const k of keys) { if (j[k] !== undefined && j[k] !== null && String(j[k]).trim() !== '') return String(j[k]).trim(); } return ''; };
const leads = items.map(({ json }) => ({
  email: pick(json, 'email', 'Email', 'EMAIL'),
  firstName: pick(json, 'first_name', 'firstName', 'First Name'),
  lastName: pick(json, 'last_name', 'lastName', 'Last Name'),
  role: pick(json, 'role', 'Role', 'title', 'Title'),
  company: pick(json, 'company', 'Company'),
  companyWebsite: pick(json, 'website', 'Website', 'companyWebsite'),
  industry: pick(json, 'industry', 'Industry'),
  source: 'sheets',
  notes: pick(json, 'notes', 'Notes'),
})).filter((l) => l.email);
const batches = [];
for (let i = 0; i < leads.length; i += 50) batches.push({ json: { leads: leads.slice(i, i + 50) } });
return batches;
